import { Module } from '@nestjs/common';
import { PetsModule } from './pets/pets.module';

@Module({ imports: [PetsModule] })
export class AppModule {}

import { Module } from '@nestjs/common';
import { PetsService } from './pets.service';
import { PetsController } from './pets.controller';

@Module({ controllers: [PetsController], providers: [PetsService] })
export class PetsModule {}

export class Pet {
  id: string;
  name: string;
  species?: string;
  age: number;
}

import { IsString, MinLength, IsOptional, IsNumber, IsPositive } from 'class-validator';
export class CreatePetDto {
  @IsString()
  @MinLength(2)
  name: string;

  @IsOptional()
  @IsString()
  species?: string;

  @IsNumber()
  @IsPositive()
  age: number;
}

import { PartialType } from '@nestjs/mapped-types';
import { CreatePetDto } from './create-pet.dto';
export class UpdatePetDto extends PartialType(CreatePetDto) {}

import { Injectable, NotFoundException } from '@nestjs/common';
import { CreatePetDto } from './dto/create-pet.dto';
import { UpdatePetDto } from './dto/update-pet.dto';
import { Pet } from './entities/pet.entity';
import { v4 as uuid } from 'uuid';

@Injectable()
export class PetsService {
  private pets: Pet[] = [];

  create(createPetDto: CreatePetDto) {
    const newPet: Pet = {
      id: uuid(),
      name: createPetDto.name,
      species: createPetDto.species,
      age: createPetDto.age,
    };
    this.pets.push(newPet);
    return newPet;
  }

  findAll() { return this.pets; }

  findOne(id: string) {
    const pet = this.pets.find(p => p.id === id);
    if (!pet) throw new NotFoundException('Pet not found');
    return pet;
  }

  update(id: string, updatePetDto: UpdatePetDto) {
    const pet = this.findOne(id);
    if (updatePetDto.name !== undefined) pet.name = updatePetDto.name;
    if (updatePetDto.species !== undefined) pet.species = updatePetDto.species;
    if (updatePetDto.age !== undefined) pet.age = updatePetDto.age;
    return pet;
  }

  remove(id: string) {
    const index = this.pets.findIndex(p => p.id === id);
    if (index === -1) throw new NotFoundException('Pet not found');
    const removed = this.pets.splice(index, 1);
    return removed[0];
  }
}

import { Controller, Get, Post, Body, Patch, Param, Delete, ParseUUIDPipe } from '@nestjs/common';
import { PetsService } from './pets.service';
import { CreatePetDto, UpdatePetDto } from './dto';

@Controller('pets')
export class PetsController {
  constructor(private readonly petsService: PetsService) {}

  @Post()
  create(@Body() createPetDto: CreatePetDto) {
    return this.petsService.create(createPetDto);
  }

  @Get()
  findAll() {
    return this.petsService.findAll();
  }

  @Get(':id')
  findOne(@Param('id', new ParseUUIDPipe({ version: '4' })) id: string) {
    return this.petsService.findOne(id);
  }

  @Patch(':id')
  update(@Param('id', new ParseUUIDPipe({ version: '4' })) id: string, @Body() updatePetDto: UpdatePetDto) {
    return this.petsService.update(id, updatePetDto);
  }

  @Delete(':id')
  remove(@Param('id', new ParseUUIDPipe({ version: '4' })) id: string) {
    return this.petsService.remove(id);
  }
}

