import { Test } from '@nestjs/testing';
import { AppModule } from './src/app.module';
import { NotFoundException } from '@nestjs/common';
import * as fs from 'fs';

async function test() {
  try {
    if (!fs.existsSync('./src/pets/pets.controller.ts')) throw new Error('[VALIDATION_ERROR] Falta pets.controller.ts');
    if (!fs.existsSync('./src/pets/pets.service.ts')) throw new Error('[VALIDATION_ERROR] Falta pets.service.ts');
    if (!fs.existsSync('./src/pets/dto/create-pet.dto.ts')) throw new Error('[VALIDATION_ERROR] Falta create-pet.dto.ts');
    if (!fs.existsSync('./src/pets/dto/index.ts')) throw new Error('[VALIDATION_ERROR] Falta index.ts en la carpeta dto');

    const controllerCode = fs.readFileSync('./src/pets/pets.controller.ts', 'utf8');
    if (!controllerCode.includes('ParseUUIDPipe')) throw new Error('[VALIDATION_ERROR] Debes usar ParseUUIDPipe en el controlador');
    if (!controllerCode.includes('./dto')) throw new Error('[VALIDATION_ERROR] Debes usar el Barrel File para importar los DTOs en el controlador');

    const mainCode = fs.readFileSync('./src/main.ts', 'utf8');
    if (!mainCode.includes('ValidationPipe')) throw new Error('[VALIDATION_ERROR] Debes configurar el ValidationPipe global en main.ts');

    const dtoCode = fs.readFileSync('./src/pets/dto/create-pet.dto.ts', 'utf8');
    if (!dtoCode.includes('IsString') || !dtoCode.includes('MinLength') || !dtoCode.includes('IsNumber') || !dtoCode.includes('IsPositive')) throw new Error('[VALIDATION_ERROR] Faltan validadores (IsString, IsNumber, IsPositive) en el DTO');

    const { PetsController } = await import('./src/pets/pets.controller');
    const { PetsService } = await import('./src/pets/pets.service');
    const moduleRef = await Test.createTestingModule({ imports: [AppModule] }).compile();

    let controller: any = moduleRef.get(PetsController, { strict: false });
    let service: any = moduleRef.get(PetsService, { strict: false });

    const newPetPayload = { name: 'Firulais', species: 'Dog', age: 3 };
    const createdPet = await controller.create(newPetPayload);
    if (!createdPet || typeof createdPet.id !== 'string' || createdPet.name !== 'Firulais') {
      throw new Error('[VALIDATION_ERROR] create() no devolvió el objeto correcto o no generó un ID string (UUID)');
    }

    let threwNotFound = false;
    try {
      await controller.findOne('abcd-efgh');
    } catch (e: any) {
      if (e instanceof NotFoundException) threwNotFound = true;
    }
    if (!threwNotFound) throw new Error('[VALIDATION_ERROR] findOne con ID inválido debe lanzar NotFoundException');

    console.log('Test pasado correctamente');
  } catch (e: any) {
    throw e;
  }
}
test();
